const rows = $input.all().map((item) => item.json ?? {});
if (!rows.length) {
  throw new Error('The cloud labels query returned no rows.');
}

const batchIds = [...new Set(rows.map((row) => String(row.batch_id ?? '').trim()).filter(Boolean))];
if (!batchIds.length) {
  throw new Error('The cloud labels query did not return a batch id.');
}
const batchId = batchIds.length === 1 ? batchIds[0] : `multiple-${batchIds.join('-')}`;

const escapeHtml = (value) => String(value ?? '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/"/g, '&quot;')
  .replace(/'/g, '&#39;');

const text = (value) => String(value ?? '').trim();
const labels = rows.map((row) => ({
  payer: text(row.payer),
  address1: text(row['Address 1']),
  address2: text(row['Address 2']),
  town: text(row.town),
  postcode: text(row.postcode).toUpperCase(),
  parentTags: Number(row.parent_tags ?? 0),
  regularTags: Number(row.regular_tags ?? 0),
  keyTags: Number(row.key_tags ?? 0),
  totalItems: Number(row.total_items ?? 0),
}));

const blankLabel = '<div class="label blank"></div>';
const pageSize = 21;
const sheets = [];
for (let i = 0; i < labels.length; i += pageSize) {
  const chunk = labels.slice(i, i + pageSize);
  while (chunk.length < pageSize) chunk.push(null);
  sheets.push(chunk);
}

const renderLabel = (label) => {
  if (!label) return blankLabel;
  const lines = [label.address1, label.address2, label.town].filter(Boolean);
  const counts = [];
  if (label.parentTags) counts.push(`${label.parentTags} parent`);
  if (label.regularTags) counts.push(`${label.regularTags} regular`);
  if (label.keyTags) counts.push(`${label.keyTags} key`);
  const countsText = counts.length ? escapeHtml(counts.join(' / ')) : '';
  return `
    <div class="label">
      <div class="line payer">${escapeHtml(label.payer)}</div>
      ${lines.map((line) => `<div class="line">${escapeHtml(line)}</div>`).join('')}
      <div class="line postcode">${escapeHtml(label.postcode)}</div>
      ${countsText ? `<div class="line meta">${countsText}</div>` : ''}
    </div>`;
};

const html = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <title>J8160 Labels</title>
  <style>
    @page {
      size: A4;
      margin: 0;
    }
    * {
      box-sizing: border-box;
    }
    html, body {
      margin: 0;
      padding: 0;
      width: 210mm;
      background: #fff;
    }
    body {
      font-family: Arial, Helvetica, sans-serif;
      color: #000;
      -webkit-print-color-adjust: exact;
      print-color-adjust: exact;
    }
    .sheet {
      width: 210mm;
      height: 297mm;
      padding: 15.1mm 0 0 7.1mm;
      display: grid;
      grid-template-columns: repeat(3, 63.5mm);
      grid-auto-rows: 38.1mm;
      column-gap: 2.65mm;
      row-gap: 0;
      page-break-after: always;
    }
    .sheet:last-child {
      page-break-after: auto;
    }
    .label {
      width: 63.5mm;
      height: 38.1mm;
      padding: 3.6mm 3.6mm 2.8mm 3.6mm;
      overflow: hidden;
      display: flex;
      flex-direction: column;
      justify-content: center;
    }
    .blank {
      visibility: hidden;
    }
    .line {
      line-height: 1.15;
      font-size: 10.6pt;
      white-space: nowrap;
      overflow: hidden;
      text-overflow: ellipsis;
    }
    .payer {
      font-weight: 700;
      margin-bottom: 0.9mm;
    }
    .postcode {
      margin-top: 0.9mm;
      font-weight: 700;
      letter-spacing: 0.3px;
    }
    .meta {
      margin-top: 1.1mm;
      font-size: 7.7pt;
      color: #444;
    }
  </style>
</head>
<body>
  ${sheets.map((sheet) => `<section class="sheet">${sheet.map(renderLabel).join('')}</section>`).join('')}
</body>
</html>`;

return [{
  json: {
    batch_id: batchId,
    label_count: labels.length,
    page_count: sheets.length,
    labels,
  },
  binary: {
    data: {
      data: Buffer.from(html, 'utf8').toString('base64'),
      mimeType: 'text/html',
      fileName: 'index.html',
      fileExtension: 'html',
    },
  },
}];

const item = $input.first();
const binary = item.binary?.data;
if (!binary?.data) {
  throw new Error('Gotenberg did not return a PDF binary payload.');
}
const batchId = String(item.json?.batch_id ?? 'unknown').replace(/[^A-Za-z0-9_-]+/g, '-');
return [{
  json: {
    ...(item.json ?? {}),
    generated_at: new Date().toISOString(),
  },
  binary: {
    data: {
      ...binary,
      mimeType: 'application/pdf',
      fileName: `j8160-labels-batch-${batchId}.pdf`,
      fileExtension: 'pdf',
    },
  },
}];
